var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"당신이...... 학회장이라고요?","JPN":"あなたが……学会長なのですか？","ENG":"You're the new President?","TWN":"妳就是……學會長？"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"네. 부족한 몸이지만 학회장의 직무를 대신하고 있어요.","JPN":"ええ。未熟者ですが、学会長の職務を代行しております。","ENG":"Yes, currently fulfilling the duties of the President.","TWN":"是的。雖然有很多不足的地方，但目前正代理學會長的職務。"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그렇다면 당신이 제게 어머니의 부고를 전했단 말이군요.","JPN":"ならば、あなたが私にお母様の訃報を送ったということですわね。","ENG":"So you sent me the letter bearing the news of my mother's death.","TWN":"那就是妳發母親的訃告給我的囉。"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"맞아요. 깃펜을 들고 며칠 동안 고민한 끝에 적어 내려갔답니다.","JPN":"はい。羽ペンを握り何日も悩んだ末に書かせていただきました。","ENG":"Yes. It took days to select the proper words to write in the letter.","TWN":"是的。拿著羽毛筆苦思了幾天，最終寫下了這封信。"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"직접 쓴 편지여야 진심이 전해지는 법이라고, 전임 학회장이셨던 맥크레디 부인께서 가르쳐 주셨거든요.","JPN":"直筆の手紙でないと真心は伝わらないと、\\n先代の学会長でいらしたマクレディー夫人が教えてくださいましたから。","ENG":"The former President, Mrs. MacCready, used to say the only way to deliver sincere sympathy was through a hand-written letter.","TWN":"因為只有親筆寫的信才能表達誠意，這是前任學會長麥克蕾蒂夫人教我們的。"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그래요? 어머니께서 그런 말씀도 할 줄 아셨군요.","JPN":"そうですの？　お母様はそのようなことを言う人だったのですね。","ENG":"She did? I didn't know my mother was capable of saying such things.","TWN":"是嗎？母親也會講這些事情啊。"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"괜찮으세요, 레지나 님? 어딘가 몸이 편찮으신가요?","JPN":"大丈夫ですか、レジーナ様？　どこか具合でも悪いのですか？","ENG":"Are you feeling all right, Miss Regina? Any difficulties?","TWN":"您還好嗎，蕾佳娜大人？身體有不舒服的地方嗎？"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"아뇨. 예상과 달라서요.","JPN":"いいえ。予想と違ったので。","ENG":"I'm fine. It's just that you're different than what I expected.","TWN":"沒有。和我預想的不一樣呢。"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"전 신임 학회장도 어머니를 닮은 마귀할멈일 거라고 생각했어요.","JPN":"私は新任の学会長も、母と同じく魔女のような人だろうと思っていました。","ENG":"I thought the new President would look like a witch of some kind, just like my mother.","TWN":"我本來以為新任學會長會是個和母親一樣的魔鬼老太婆。"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"하지만 그렇게 보이진 않는군요.","JPN":"でも、そのようには見えませんね。","ENG":"But you don't seem like that in any way.","TWN":"但看起來並非如此。"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"레지나 님께서 마음에 든다고 하시니 기쁘네요.","JPN":"お気に召したようで何よりです。","ENG":"It's so relieving to know that you have a good impression of us.","TWN":"能得到蕾佳娜大人的青睞，我們感到非常高興。"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L15_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"......착각하진 말아 주세요. 당신을 인정한다는 뜻은 아닙니다.","JPN":"……勘違いしないでくださいね。あなたを認めるという意味ではありませんわ。","ENG":"But let me be clear: It doesn't mean that I acknowledge you.","TWN":"……請不要誤會。這並不是認可妳的意思。"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L16_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"제가 여기 온 건 장례식 때문만이 아니에요. 학회와 연을 끊기 위해서죠.","JPN":"私がここに来た目的は葬儀だけではありません。学会と縁を切るためです。","ENG":"I didn't come here just for the funeral. Another reason I'm here is to cut my connection with the Society for good.","TWN":"我到這裡來不只是為了葬禮，同時也是為了和學會斷絕關係。"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L18_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"그렇지만 맥크레디 가문은 대대로 학회장직을 역임해 온 집안이잖아요.","JPN":"ですが、マクレディー家は代々学会長を歴任してきた家系のはずです。","ENG":"But it was always members of the MacCready family that served as the President of the Society.","TWN":"但是麥克蕾蒂家族代代都會擔任學會長啊。"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"맥크레디 부인께서도 레지나 님을 차기 학회장으로 지목하셨어요.","JPN":"マクレディー夫人もレジーナ様を次期学会長に指名しておられました。","ENG":"It was you that Mrs. MacCready wanted to appoint as the next President.","TWN":"麥克蕾蒂夫人也指定蕾佳娜大人為下任學會長。"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"따님께서 전통을 버리시면 섭섭해 하실 거예요.","JPN":"お嬢様が伝統を捨ててしまうと悲しまれるでしょう。","ENG":"She'll be sad if you were to abandon the family tradition.","TWN":"如果女兒拋棄了這個傳統，麥克蕾蒂夫人會很傷心吧。"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"전 차기 학회장이 되겠다고 한 적도 없고, 더 이상 가문이 학회에 놀아나게 놔둘 생각도 없어요.","JPN":"私は次期学会長になると言ったこともなければ、\\nこれ以上マクレディー家が学会に弄ばれるのを黙って見ているつもりもありません。","ENG":"I never wanted to be the President, and I won't let my family be fooled by the Society.","TWN":"我從來沒說過自己要成為下任學會長，也不打算放任家族繼續受到學會的擺佈。"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"어머니를 들먹여 봤자 마찬가집니다. 저와 어머니는 그리 좋은 관계가 아니거든요.","JPN":"母をダシにしても無駄ですわ。私と母はそんなに良い関係ではありませんでしたから。","ENG":"Bringing my mother into the conversation won't make any difference. Mom and I have never been on good terms.","TWN":"就算妳拿母親壓我也沒用。我和母親的關係並沒有那麼好。"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_DESPAIR"}}}}]`);export{e as default};